// Filter contacts who haven't engaged in 45, 60, or 90+ days
const today = new Date();
const msPerDay = 24 * 60 * 60 * 1000;

const contacts = $input.all();
const reengagementCandidates = [];

for (const wrapper of contacts) {
  const c = wrapper.json;

  // Skip already opted-out
  const tags = c.tags || [];
  if (tags.includes('Unsubscribed') || tags.includes('Do Not Contact')) continue;

  // Check last engagement date (from custom field or tag)
  const lastEngagedField = c.customFields?.find(f => f.key === 'last_engaged_date');
  const lastContactedField = c.customFields?.find(f => f.key === 'last_contacted_date');

  const lastEngaged = lastEngagedField?.value 
    ? new Date(lastEngagedField.value)
    : lastContactedField?.value 
      ? new Date(lastContactedField.value)
      : null;

  if (!lastEngaged || isNaN(lastEngaged.getTime())) {
    // No engagement data - use creation date as proxy
    const created = new Date(c.dateAdded || c.created_at || today);
    const daysSince = Math.round((today - created) / msPerDay);

    if (daysSince >= 45) {
      reengagementCandidates.push({
        ...c,
        lastDate: created,
        daysSince,
        tier: daysSince >= 90 ? 'dormant-90' : daysSince >= 60 ? 'dormant-60' : 'dormant-45',
        attemptNumber: 0,
        daysSinceCategory: `${daysSince} days since creation`
      });
    }
    continue;
  }

  const daysSince = Math.round((today - lastEngaged) / msPerDay);

  if (daysSince >= 45) {
    // Count previous re-engagement attempts from tags
    const reengageTag = tags.find(t => t.startsWith('Re-engagement Attempt'));
    const attemptNumber = reengageTag 
      ? parseInt(reengageTag.split(' ').pop()) || 1 
      : 0;

    // Skip if already attempted 3 times
    if (attemptNumber >= 3) continue;

    reengagementCandidates.push({
      ...c,
      lastEngaged: lastEngaged.toISOString(),
      daysSince,
      tier: daysSince >= 90 ? 'dormant-90' : daysSince >= 60 ? 'dormant-60' : 'dormant-45',
      attemptNumber,
      daysSinceCategory: `${daysSince} days since last engagement`
    });
  }
}

// Sort by tier (most dormant first) and limit
return reengagementCandidates
  .sort((a, b) => b.daysSince - a.daysSince)
  .slice(0, 30);

// Generate re-engagement email based on tier and previous attempts
const c = $input.first().json;
const attempt = c.attemptNumber || 0;

const variants = [
  // Variant 1 - Value focused
  {
    subject: `Checking in, ${c.firstName || 'Friend'} - Quick question about your coverage`,
    html: `<h1>Hi ${c.firstName || 'there'},</h1><p>I wanted to check in and see how things are going with your insurance coverage.</p><p>Have your needs changed recently? Have you moved, experienced a major life event, or is your current coverage still meeting your needs?</p><p>I'd be happy to do a free, no-obligation review of your coverage — just reply to this email or <a href="https://buckalewfinancialservices.com/schedule">book a call</a>.</p><p>Warm regards,<br/>The Buckalew Financial Team</p>`
  },
  // Variant 2 - Educational
  {
    subject: `Medicare & Insurance Update: What ${c.firstName ? c.firstName.split(' ')[0] : 'You'} Should Know`,
    html: `<h1>Hi ${c.firstName || 'there'},</h1><p>I was thinking of you and wanted to share some important updates in the insurance world that might affect you:</p><ul><li>💰 Medicare costs are changing — make sure you're not overpaying</li><li>📅 Annual Enrollment is a great time to review your coverage</li><li>🏥 New benefits may be available to you</li></ul><p><a href="https://buckalewfinancialservices.com/resources">Click here for our free resource guide</a></p><p>Questions? Just reply — I'm here to help!<br/>Warm regards,<br/>The Buckalew Financial Team</p>`
  },
  // Variant 3 - Direct CTA
  {
    subject: `Still there, ${c.firstName || 'Friend'}? Claim your free plan review`,
    html: `<h1>Hi ${c.firstName || 'there'},</h1><p>We've noticed you haven't connected with us in a while, and we just wanted to make sure we're still here for you.</p><p>If you're all set with your insurance, just ignore this email — no hard feelings!</p><p>But if you've got questions, need a quote, or want to make sure you're not missing out on savings, <strong>I'd love to hear from you.</strong></p><p><a href="https://buckalewfinancialservices.com/schedule">👉 Schedule a free 15-minute call</a></p><p>Talk soon!<br/>The Buckalew Financial Team</p>`
  }
];

// Rotate variants based on attempt number
const variant = variants[attempt % variants.length];

return {
  ...c,
  subject: variant.subject,
  html: variant.html,
  attemptNumber: attempt + 1,
  variantIndex: attempt % variants.length
};

